/** @type {import('../../..').TextfieldMask} */
export default {
  mask: 'N',
  tokens: {
    N: { pattern: /\d/, multiple: true },
    D: { pattern: /\d/, optional: true },
  },
  preProcess: val => val.replace(/\./g, ''),
  postProcess: val => {
    if (!val) return '';
    const sub = 3 - (val.includes(',') ? val.length - val.indexOf(',') : 0);

    /**
     * Change to AR format due to Node 20 CI tests failing with CO format.
     * see https://github.com/melisource/fury_frontend-andes-ui/pull/2174
     */
    return Intl.NumberFormat('es-AR', {
      style: 'currency',
      currency: 'ARS',
    }).format(Number(val.replace(',', '.'))).replace('$', '').replace(/\s/g, '')
      .slice(0, sub ? -sub : undefined);
  },
};
